SELECT * FROM b_inventory_warning


        AND (INSTR(material_code, #{query.searchWord}) OR INSTR(material_name, #{query.searchWord}))


        AND INSTR(material_name, #{query.materialName})


        AND warning_type = #{query.warningType}


        AND warning_level = #{query.warningLevel}


        AND handle_status = #{query.handleStatus}


ORDER BY warning_level DESC, create_time DESC

SELECT * FROM b_inventory_warning
WHERE material_id = #{materialId}
AND warning_type = #{warningType}
AND handle_status = #{handleStatus}
LIMIT 1
